{"command": "cd /Users/arsapolm/.nanobot-npa-guy/workspace && psql postgresql://arsapolm@localhost:5432/npa_kb -c "
-- How many KBANK Bangkok condos total?
SELECT COUNT(*) FROM kbank_properties 
WHERE property_type_name ILIKE '%%ห้องชุด%%' AND province_name ILIKE '%%กรุงเทพ%%';

-- How many with GPS?
SELECT COUNT(*) FROM kbank_properties 
WHERE property_type_name ILIKE '%%ห้องชุด%%' AND province_name ILIKE '%%กรุงเทพ%%' AND lat IS NOT NULL;

-- Distribution by amphur
SELECT amphur_name, COUNT(*) FROM kbank_properties 
WHERE property_type_name ILIKE '%%ห้องชุด%%' AND province_name ILIKE '%%กรุงเทพ%%'
GROUP BY amphur_name ORDER BY count DESC LIMIT 15;
" 2>&1", "timeout": 10}

{"command": "cd /Users/arsapolm/.nanobot-npa-guy/workspace && psql postgresql://arsapolm@localhost:5432/npa_kb -c "
-- JAM: Check type_sale (sale vs rental distribution)
SELECT type_sale_th, COUNT(*) FROM jam_properties GROUP BY type_sale_th ORDER BY count DESC LIMIT 10;

-- JAM: Check if there are SALE properties in Bangkok
SELECT type_sale_th, type_asset_th, COUNT(*) 
FROM jam_properties 
WHERE province ILIKE '%%กรุงเทพ%%'
GROUP BY type_sale_th, type_asset_th 
ORDER BY count DESC LIMIT 20;
" 2>&1", "timeout": 10}

