SELECT type_sale_th, COUNT(*) FROM jam_properties 
WHERE province_name = 'กรุงเทพมหานคร'
GROUP BY type_sale_th;

-- JAM Bangkok SALE: property type distribution
SELECT type_asset_th, COUNT(*) FROM jam_properties 
WHERE province_name = 'กรุงเทพมหานคร' AND type_sale_th = 'ขาย'
GROUP BY type_asset_th ORDER BY count DESC LIMIT 15;
" 2>&1", "timeout": 10}

